#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    for(int i=0;i<T;++i){
        int X,Y; scanf("%d %d", &X, &Y);
        if(X>Y) printf("FREEKICK\n");
        else printf("PENALTY\n");
    }
    return 0;
}

